from .quant5b import build_grid, _build_grid
# per-(kind, device) cache of constant tensors
_IQ2_CONST_CACHE = {}
def _iq_consts(kind, device):  # renamed from _iq2_consts; update existing callers
    key = (kind, str(device))
    c = _IQ2_CONST_CACHE.get(key)
    if c is None:
        if kind == "iq2_xxs":
            grid = build_grid(IQ2_XXS_GRID_HEX, IQ2_XXS_GRID_SHAPE, IQ2_GRID_MAP)
        elif kind == "iq2_xs":
            grid = build_grid(IQ2_XS_GRID_HEX, IQ2_XS_GRID_SHAPE, IQ2_GRID_MAP)
        elif kind == "iq2_s":
            grid = build_grid(IQ2_S_GRID_HEX, IQ2_S_GRID_SHAPE, IQ2_GRID_MAP)
        elif kind == "iq3_xxs":
            grid = _build_grid(IQ3_XXS_GRID_HEX, IQ3_XXS_GRID_SHAPE, IQ3_XXS_GRID_MAP)
        elif kind == "iq3_s":
            grid = _build_grid(IQ3_S_GRID_HEX, IQ3_S_GRID_SHAPE, IQ3_S_GRID_MAP)
        else:
            raise ValueError(kind)
        c = {
            "grid": grid.to(device),
            "ksigns": torch.tensor(list(IQ2_KSIGNS), dtype=torch.int64, device=device),
            "bits": torch.arange(8, dtype=torch.int64, device=device),
            "sh_0_7_14_21": torch.tensor([0, 7, 14, 21], dtype=torch.int64, device=device),
            "sh_0_8_16_24": torch.tensor([0, 8, 16, 24], dtype=torch.int64, device=device),
            "sh_0_4": torch.tensor([0, 4], dtype=torch.int64, device=device),
            "sh_0_2_4_6": torch.tensor([0, 2, 4, 6], dtype=torch.int64, device=device),
        }
        _IQ2_CONST_CACHE[key] = c
    return c
def _signs_from_bytes(sign_bytes, bits):
    s = (sign_bytes.unsqueeze(-1) >> bits) & 1
    return 1.0 - 2.0 * s.to(torch.float32)
def dequantize_blocks_IQ2_XXS(blocks, block_size=QK_K, type_size=None, dtype=None):
    n_blocks = blocks.shape[0]
    # c = _iq2_consts("iq2_xxs", blocks.device)
    c = _iq_consts("iq2_xxs", blocks.device)
    d, qs = split_block_dims(blocks, 2)
    d = d.contiguous().view(torch.float16).to(torch.float32)          # (n, 1)
    qs = _to_uint32(qs.reshape(n_blocks, -1, 2, 4))                   # (n, 8, 2)
    # scales: top 4 bits of the second u32 of each pair
    db = d * (0.5 + (qs[..., 1] >> 28).to(torch.float32)) * 0.25      # (n, 8)
    db = db.reshape(n_blocks, -1, 1, 1)
    # signs: 4x 7-bit indices into ksigns, then unpack 8 sign bits each
    sidx = (qs[..., 1].unsqueeze(-1) >> c["sh_0_7_14_21"]) & 0x7F     # (n, 8, 4)
    signs = _signs_from_bytes(c["ksigns"][sidx], c["bits"])           # (n, 8, 4, 8)
    # grid: the first u32 of each pair holds 4 byte-indices into the 256x8 grid
    gidx = (qs[..., 0].unsqueeze(-1) >> c["sh_0_8_16_24"]) & 0xFF     # (n, 8, 4)
    grid = c["grid"][gidx]                                            # (n, 8, 4, 8)
    out = (db * grid * signs).reshape(n_blocks, -1)
    if dtype is not None:
        out = out.to(dtype)
    return out
def dequantize_blocks_IQ2_XS(blocks, block_size=QK_K, type_size=None, dtype=None):
    n_blocks = blocks.shape[0]
    # c = _iq2_consts("iq2_xs", blocks.device)
    c = _iq_consts("iq2_xs", blocks.device)
    d, qs, scales = split_block_dims(blocks, 2, 2 * QK_K // 8)
    d = d.contiguous().view(torch.float16).to(torch.float32)          # (n, 1)
    qs = _to_uint16(qs.reshape(n_blocks, -1, 2))                      # (n, 32)
    scales = (scales.to(torch.int64).unsqueeze(-1) >> c["sh_0_4"]) & 0x0F
    scales = scales.reshape(n_blocks, -1).to(torch.float32)           # (n, 16)
    db = (d * (0.5 + scales) * 0.25).reshape(n_blocks, -1, 1, 1)      # (n, 16, 1, 1)
    # signs: top 7 bits of each u16 index into ksigns
    signs = _signs_from_bytes(c["ksigns"][qs >> 9], c["bits"])        # (n, 32, 8)
    signs = signs.reshape(n_blocks, -1, 2, 8)                         # (n, 16, 2, 8)
    # grid: low 9 bits of each u16 index into the 512x8 grid
    grid = c["grid"][qs & 511].reshape(n_blocks, -1, 2, 8)            # (n, 16, 2, 8)
    out = (db * grid * signs).reshape(n_blocks, -1)
    if dtype is not None:
        out = out.to(dtype)
    return out
def dequantize_blocks_IQ2_S(blocks, block_size=QK_K, type_size=None, dtype=None):
    n_blocks = blocks.shape[0]
    # c = _iq2_consts("iq2_s", blocks.device)
    c = _iq_consts("iq2_s", blocks.device)
    d, qs, signs, qh, scales = split_block_dims(
        blocks, 2, QK_K // 8, QK_K // 8, QK_K // 32
    )
    d = d.contiguous().view(torch.float16).to(torch.float32)          # (n, 1)
    scales = (scales.to(torch.int64).unsqueeze(-1) >> c["sh_0_4"]) & 0x0F
    scales = scales.reshape(n_blocks, -1).to(torch.float32)           # (n, 16)
    db = (d * (0.5 + scales) * 0.25).reshape(n_blocks, -1, 1, 1)      # (n, 16, 1, 1)
    # signs are stored explicitly, one bit per value
    signs = _signs_from_bytes(signs.to(torch.int64), c["bits"])       # (n, 32, 8)
    signs = signs.reshape(n_blocks, -1, 2, 8)                         # (n, 16, 2, 8)
    # grid index: 8 low bits from qs plus 2 high bits from qh -> 10-bit index
    qh = (qh.to(torch.int64).unsqueeze(-1) >> c["sh_0_2_4_6"]) & 0x03  # (n, 8, 4)
    gidx = qs.to(torch.int64) | (qh.reshape(n_blocks, -1) << 8)       # (n, 32)
    grid = c["grid"][gidx].reshape(n_blocks, -1, 2, 8)                # (n, 16, 2, 8)
    out = (db * grid * signs).reshape(n_blocks, -1)
    if dtype is not None:
        out = out.to(dtype)
    return out
def dequantize_blocks_IQ3_XXS(blocks, block_size=QK_K, type_size=None, dtype=None):
    n_blocks = blocks.shape[0]
    c = _iq_consts("iq3_xxs", blocks.device)
    d, rest = split_block_dims(blocks, 2)
    qs, scales = split_block_dims(rest, QK_K // 4)
    d = d.contiguous().view(torch.float16).to(torch.float32)          # (n, 1)
    qs = qs.contiguous().to(torch.int64)                              # (n, 64) grid row indices
    scales = _to_uint32(scales.reshape(n_blocks, -1, 4))              # (n, 8)
    # scales: top 4 bits of each u32
    db = d * (0.5 + (scales >> 28).to(torch.float32)) * 0.5           # (n, 8)
    db = db.reshape(n_blocks, -1, 1, 1)
    # signs: 4x 7-bit indices into ksigns, then unpack 8 sign bits each
    sidx = (scales.unsqueeze(-1) >> c["sh_0_7_14_21"]) & 0x7F         # (n, 8, 4)
    signs = _signs_from_bytes(c["ksigns"][sidx], c["bits"])           # (n, 8, 4, 8)
    # grid: each qs byte indexes a row of the 256x4 grid
    grid = c["grid"][qs].reshape(n_blocks, -1, 4, 8)                  # (n, 8, 4, 8)
    out = (db * grid * signs).reshape(n_blocks, -1)
    if dtype is not None:
        out = out.to(dtype)
    return out
def dequantize_blocks_IQ3_S(blocks, block_size=QK_K, type_size=None, dtype=None):
    n_blocks = blocks.shape[0]
    c = _iq_consts("iq3_s", blocks.device)
    d, rest = split_block_dims(blocks, 2)
    qs, rest = split_block_dims(rest, QK_K // 4)
    qh, rest = split_block_dims(rest, QK_K // 32)
    signs, scales = split_block_dims(rest, QK_K // 8)
    d = d.contiguous().view(torch.float16).to(torch.float32)          # (n, 1)
    # scales: two 4-bit nibbles per byte -> 1 + 2*s
    scales = scales.contiguous().to(torch.int64)                      # (n, 4)
    scales = (scales.unsqueeze(-1) >> c["sh_0_4"]) & 0x0F             # (n, 4, 2)
    db = d * (1 + 2 * scales.reshape(n_blocks, -1).to(torch.float32)) # (n, 8)
    db = db.reshape(n_blocks, -1, 1, 1)
    # signs: raw per-bit sign bytes (no ksigns lookup)
    signs = _signs_from_bytes(signs.contiguous().to(torch.int64), c["bits"])  # (n, 32, 8)
    signs = signs.reshape(n_blocks, -1, 4, 8)                         # (n, 8, 4, 8)
    # grid index: qs byte + high bit from qh -> 9-bit index into 512x4 grid
    qh = (qh.contiguous().to(torch.int64).unsqueeze(-1) >> c["bits"]) & 1     # (n, 8, 8)
    qs = qs.contiguous().to(torch.int64) | (qh.reshape(n_blocks, -1) << 8)    # (n, 64)
    grid = c["grid"][qs].reshape(n_blocks, -1, 4, 8)                  # (n, 8, 4, 8)
    out = (db * grid * signs).reshape(n_blocks, -1)
    if dtype is not None:
        out = out.to(dtype)
    return out
def dequantize_blocks_IQ4_NL(blocks, block_size, type_size, dtype=None):
    kvalues = torch.tensor([-127, -104, -83, -65, -49, -35, -22, -10, 1, 13,
        25, 38, 53, 69, 89, 113], dtype=torch.float32, device=blocks.device)
    n_blocks = blocks.shape[0]
    d, qs = split_block_dims(blocks, 2)
    d = d.view(torch.float16).to(dtype)
    qs = qs.reshape((n_blocks, -1, 1, block_size // 2)) >> torch.tensor([0,
        4], device=blocks.device, dtype=torch.uint8).reshape((1, 1, 2, 1))
    qs = (qs & 15).reshape((n_blocks, -1)).to(torch.int64)
    kvalues = kvalues.view(1, 1, 16)
    qs = qs.unsqueeze(-1)
    qs = torch.gather(kvalues.expand(qs.shape[0], qs.shape[1], 16), 2, qs)
    qs = qs.squeeze(-1).to(dtype)
    return d * qs
def dequantize_blocks_IQ4_XS(blocks, block_size, type_size, dtype=None):
    kvalues = torch.tensor([-127, -104, -83, -65, -49, -35, -22, -10, 1, 13,
        25, 38, 53, 69, 89, 113], dtype=torch.float32, device=blocks.device)
    n_blocks = blocks.shape[0]
    d, scales_h, scales_l, qs = split_block_dims(blocks, 2, 2, QK_K // 64)
    d = d.view(torch.float16).to(dtype)
    scales_h = scales_h.view(torch.int16)
    scales_l = scales_l.reshape((n_blocks, -1, 1)) >> torch.tensor([0, 4],
        device=blocks.device, dtype=torch.uint8).reshape((1, 1, 2))
    scales_h = scales_h.reshape((n_blocks, 1, -1)) >> torch.tensor([(2 * i) for
        i in range(QK_K // 32)], device=blocks.device, dtype=torch.uint8
        ).reshape((1, -1, 1))
    scales_l = scales_l.reshape((n_blocks, -1)) & 15
    scales_h = scales_h.reshape((n_blocks, -1)) & 3
    scales = (scales_l | scales_h << 4) - 32
    dl = (d * scales.to(dtype)).reshape((n_blocks, -1, 1))
    shifts_q = torch.tensor([0, 4], device=blocks.device, dtype=torch.uint8
        ).reshape(1, 1, 2, 1)
    qs = qs.reshape((n_blocks, -1, 1, 16)) >> shifts_q
    qs = (qs & 15).reshape((n_blocks, -1, 32)).to(torch.int64)
    kvalues = kvalues.view(1, 1, 1, 16)
    qs = qs.unsqueeze(-1)
    qs = torch.gather(kvalues.expand(qs.shape[0], qs.shape[1], qs.shape[2],
        16), 3, qs)
    qs = qs.squeeze(-1).to(dtype)
    return (dl * qs).reshape(n_blocks, -1)
# mxpf4 support
from .quant5b import e8m0_to_fp32_half
def dequantize_blocks_MXFP4(blocks, block_size, type_size=None, dtype=None):
    kvalues = torch.tensor(
        [0, 1, 2, 3, 4, 6, 8, 12, 0, -1, -2, -3, -4, -6, -8, -12],
        dtype=torch.float32,
        device=blocks.device,
    ).view(1, 1, 16)
    n_blocks = blocks.shape[0]
    e, qs = split_block_dims(blocks, 1)
    d = e8m0_to_fp32_half(e)
    qs = qs.reshape(n_blocks, 1, block_size // 2)
    shifts = torch.tensor(
        [0, 4],
        dtype=qs.dtype,
        device=blocks.device,
    ).reshape(1, 2, 1)
    qs = (qs >> shifts) & 15
    qs = qs.to(torch.long)
    qs = torch.gather(
        kvalues.expand(n_blocks, 2, 16),
        dim=2,
        index=qs,
    )
    qs = qs.reshape(n_blocks, block_size)
    out = d * qs
    if dtype is not None:
        out = out.to(dtype)
    return out
# nvfp4 support
from .quant5b import ue4m3_to_fp32
def dequantize_blocks_NVFP4(blocks, block_size, type_size=None, dtype=None):
    kvalues = torch.tensor(
        [0, 1, 2, 3, 4, 6, 8, 12, 0, -1, -2, -3, -4, -6, -8, -12],
        dtype=torch.float32,
        device=blocks.device,
    ).view(1, 1, 16)
    n_super = blocks.shape[0]
    d_bytes, qs = split_block_dims(blocks, 4)
    d = ue4m3_to_fp32(d_bytes).reshape(n_super, 4, 1)
    qs = qs.reshape(n_super, 4, 8)
    lo = qs & 15
    hi = qs >> 4
    vals = torch.cat([lo, hi], dim=-1).to(torch.long)
    vals = torch.gather(
        kvalues.expand(n_super, 4, 16),
        dim=2,
        index=vals,
    )
    out = (d * vals).reshape(n_super, 64)
    if dtype is not None:
        out = out.to(dtype)
    return out
